import { v4 } from 'uuid'
import createPersistedState from 'use-persisted-state';
import { getClock } from './clock';
import Timestamp from './timestamp';
import { applyMessages, sendMessages } from './sync';

let data = {}
let messages = []

function insert(table: string, row: any) {
  let id = v4();
  let fields = Object.keys(row);

  sendMessages(
    fields.map(k => {
      return {
        dataset: table,
        row: row.id || id,
        column: k,
        value: row[k],
        timestamp: Timestamp.send(getClock()).toString()
      };
    })
  );

  return id;
}

function getAll(table: string) {
  if (!data[table]) data[table] = []
  return data[table].filter(row => row.tombstone !== 1);
}

function getData() {
  return data
}

function getMessages() {
  return messages
}

function createUseDb(key: string) {
const persistedState = createPersistedState(key);
  return function useDb(table: string) {
    const [data, setData] = persistedState([])

    return [data, function insertData(row) {
      insert(table, row)
      console.log('msgs depois do insert: ', getMessages())
      setData([...data, row])
    }]
  }

}

export {
  createUseDb,
  getAll,
  getData,
  getMessages,
  insert,
}
